/// A tree-sitter parser configured for one language at a time.
///
/// # Example
#[derive(Clone)]
#[wasm_bindgen]
pub struct WasmParser {
    pub(crate) inner: Arc<std::sync::Mutex<tree_sitter_language_pack::Parser>>,
}

#[wasm_bindgen]
impl WasmParser {
    /// Construct a new parser with no language set.
    ///
    /// Call `Parser.set_language` before parsing.
    #[wasm_bindgen]
    pub fn new() -> WasmParser {
        Self {
            inner: Arc::new(std::sync::Mutex::new(tree_sitter_language_pack::Parser::new())),
        }
    }

    /// Configure the parser to use the language identified by name (e.g. `"python"`).
    ///
    /// Resolves the language through the global registry — auto-downloading
    /// if necessary, when the `download` feature is enabled.
    ///
    /// # Errors
    ///
    /// Returns `Error.LanguageNotFound` if the language is not recognized,
    /// or `Error.ParserSetup` if the language ABI is incompatible.
    #[allow(clippy::missing_errors_doc)]
    #[wasm_bindgen(js_name = "setLanguage")]
    pub fn set_language(&self, name: String) -> Result<(), JsValue> {
        self.inner
            .lock()
            .unwrap()
            .set_language(&name)
            .map_err(|e| JsValue::from_str(&e.to_string()))?;
        Ok(())
    }

    /// Parse a UTF-8 source string. Returns `None` if parsing was cancelled
    /// or no language is set.
    #[wasm_bindgen]
    pub fn parse(&self, source: String) -> Option<WasmTree> {
        self.inner
            .lock()
            .unwrap()
            .parse(&source)
            .map(|v| WasmTree { inner: Arc::new(v) })
    }

    /// Parse a raw byte slice. Returns `None` if parsing was cancelled or
    /// no language is set.
    #[wasm_bindgen(js_name = "parseBytes")]
    pub fn parse_bytes(&self, source: Vec<u8>) -> Option<WasmTree> {
        self.inner
            .lock()
            .unwrap()
            .parse_bytes(&source)
            .map(|v| WasmTree { inner: Arc::new(v) })
    }

    /// Reset internal state. The next call to `parse` will
    /// not be incremental.
    #[wasm_bindgen]
    pub fn reset(&self) -> () {
        self.inner.lock().unwrap().reset()
    }
}

