    #[wasm_bindgen]
    pub fn kind(&self) -> String {
        self.inner.kind()
    }

    /// Return the node's numeric kind ID.
    ///
    /// Tree-sitter assigns a stable `u16` ID to every node kind in a grammar
    /// (e.g. `"function_definition" → 42`). Comparing `kind_id()` is cheaper
    /// than comparing the string `kind()` in tight AST loops.
    #[wasm_bindgen(js_name = "kindId")]
    pub fn kind_id(&self) -> u16 {
        self.inner.kind_id()
    }

    /// Return the inclusive start byte offset of this node.
    #[wasm_bindgen(js_name = "startByte")]
    pub fn start_byte(&self) -> usize {
        self.inner.start_byte()
    }

    /// Return the exclusive end byte offset of this node.
    #[wasm_bindgen(js_name = "endByte")]
    pub fn end_byte(&self) -> usize {
        self.inner.end_byte()
    }

    /// Return the node's byte range as a `ByteRange`.
    ///
    /// Callers should slice their own source bytes — this is a zero-copy
    /// text accessor.
    #[wasm_bindgen(js_name = "byteRange")]
    pub fn byte_range(&self) -> WasmByteRange {
        self.inner.byte_range().into()
    }

    /// Return the start `Point` (row, column).
    #[wasm_bindgen(js_name = "startPosition")]
    pub fn start_position(&self) -> WasmPoint {
        self.inner.start_position().into()
    }

    /// Return the end `Point` (row, column).
    #[wasm_bindgen(js_name = "endPosition")]
    pub fn end_position(&self) -> WasmPoint {
        self.inner.end_position().into()
    }

    /// True when this node is named (not punctuation/whitespace).
    #[wasm_bindgen(js_name = "isNamed")]
    pub fn is_named(&self) -> bool {
        self.inner.is_named()
    }

    /// True when this is an error node.
