    pub fn is_error(&self) -> bool {
        self.inner.is_error()
    }

    /// True when this is a missing-token node.
    #[wasm_bindgen(js_name = "isMissing")]
    pub fn is_missing(&self) -> bool {
        self.inner.is_missing()
    }

    /// True when this is an "extra" node (e.g. a comment).
    #[wasm_bindgen(js_name = "isExtra")]
    pub fn is_extra(&self) -> bool {
        self.inner.is_extra()
    }

    /// True when this node or any descendant is an error.
    #[wasm_bindgen(js_name = "hasError")]
    pub fn has_error(&self) -> bool {
        self.inner.has_error()
    }

    /// Return this node's parent, if any.
    #[wasm_bindgen]
    pub fn parent(&self) -> Option<WasmNode> {
        self.inner.parent().map(|v| WasmNode { inner: Arc::new(v) })
    }

    /// Return the i-th child of this node, if any.
    #[wasm_bindgen]
    pub fn child(&self, index: u32) -> Option<WasmNode> {
        self.inner.child(index).map(|v| WasmNode { inner: Arc::new(v) })
    }

    /// Total number of children (including unnamed).
