/// Thread-safe registry of tree-sitter language parsers.
///
/// Manages both statically compiled and dynamically loaded language grammars.
/// Use `LanguageRegistry.new()` for the default registry, or access the
/// global instance via the module-level convenience functions
/// (`get_language`, `available_languages`, etc.).
///
/// # Example
#[derive(Clone)]
#[wasm_bindgen]
pub struct WasmLanguageRegistry {
    pub(crate) inner: Arc<tree_sitter_language_pack::LanguageRegistry>,
}

#[wasm_bindgen]
impl WasmLanguageRegistry {
    /// Create a new registry populated with all statically compiled languages.
    ///
    /// When the `dynamic-loading` feature is enabled, the registry also knows
    /// about dynamically loadable grammars and will load them on demand.
    #[wasm_bindgen]
    pub fn new() -> WasmLanguageRegistry {
        Self {
            inner: Arc::new(tree_sitter_language_pack::LanguageRegistry::new()),
        }
    }

    /// Get a tree-sitter `Language` by name.
    ///
    /// Resolves aliases (e.g., `"shell"` -> `"bash"`, `"makefile"` -> `"make"`),
    /// then looks up the language in the static table. When the `dynamic-loading`
    /// feature is enabled, falls back to loading a shared library on demand.
    ///
    /// # Errors
    ///
    /// Returns `Error.LanguageNotFound` if the name (after alias resolution)
    /// does not match any known grammar.
    #[allow(clippy::missing_errors_doc)]
    #[wasm_bindgen(js_name = "getLanguage")]
    pub fn get_language(&self, name: String) -> Result<WasmLanguage, JsValue> {
        let result = self
            .inner
            .get_language(&name)
            .map_err(|e| JsValue::from_str(&e.to_string()))?;
        Ok(WasmLanguage {
            inner: Arc::new(result),
        })
    }

    /// List all available language names, sorted and deduplicated.
    ///
    /// Includes statically compiled languages, dynamically loadable languages
    /// (if the `dynamic-loading` feature is enabled), and all configured aliases.
    #[wasm_bindgen(js_name = "availableLanguages")]
    pub fn available_languages(&self) -> Vec<String> {
        self.inner.available_languages()
    }

    /// Check whether a parser is statically compiled into this build.
    ///
    /// Returns `true` only when the grammar was compiled in at build time
    /// (i.e. it appears in the `STATIC_LANGUAGES` table). This is independent
    /// of the extension-to-language mapping: `detect_language_from_extension`
    /// consults the static ext table for all 306 grammars regardless of which
    /// parsers are compiled in.
    ///
    /// Use this when you need to distinguish "we know the language name" from
    /// "we can actually parse files in that language right now".
    #[wasm_bindgen(js_name = "hasParser")]
    pub fn has_parser(&self, name: String) -> bool {
        self.inner.has_parser(&name)
    }

    /// Check whether a language is available by name or alias.
    ///
    /// Returns `true` if the language can be loaded, either from the static
    /// table or from a dynamic library on disk.
    #[wasm_bindgen(js_name = "hasLanguage")]
    pub fn has_language(&self, name: String) -> bool {
        self.inner.has_language(&name)
    }

    /// Return the total number of available languages (including aliases).
    #[wasm_bindgen(js_name = "languageCount")]
    pub fn language_count(&self) -> usize {
        self.inner.language_count()
    }

    /// Parse source code and extract file intelligence based on config in a single pass.
    #[allow(clippy::missing_errors_doc)]
    #[wasm_bindgen]
    pub fn process(&self, _source: String, _config: WasmProcessConfig) -> Result<WasmProcessResult, JsValue> {
        Err(JsValue::from_str("Not implemented: process"))
    }
}

