/// The kind of a data node extracted from a data-format file.
///
/// Classifies each node in the hierarchical `DataNode` tree returned when
/// `data_extraction` is enabled on `ProcessConfig`.
///
/// # Wire format (public JSON contract)
///
/// Unit variants serialize as a bare string (`"KeyValue"`). DO NOT add
/// `#[serde(tag = "...")]` or rename variants — every language binding has a
/// hand-written deserializer matching this exact shape, and any change breaks
/// all bindings' `process()` tests simultaneously.
/// Covered by `tests/wire_format.rs`.

#[wasm_bindgen]
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum WasmDataNodeKind {
    KeyValue = 0,
    Element = 1,
    Sequence = 2,
}

#[allow(clippy::derivable_impls)]
impl Default for WasmDataNodeKind {
    fn default() -> Self {
        Self::KeyValue
    }
}

impl WasmDataNodeKind {
    /// Returns the serde wire string for this variant (e.g. `"stop"`, `"tool_calls"`).
    pub fn to_api_str(self) -> &'static str {
        match self {
            Self::KeyValue => "KeyValue",
            Self::Element => "Element",
            Self::Sequence => "Sequence",
        }
    }

    /// Parses a serde wire string and returns the corresponding variant, or None if unrecognized.
    pub fn from_api_str(s: &str) -> Option<Self> {
        match s {
            "KeyValue" => Some(Self::KeyValue),
            "Element" => Some(Self::Element),
            "Sequence" => Some(Self::Sequence),
            _ => None,
        }
    }
}

/// The kind of structural item found in source code.
///
/// Categorizes top-level and nested declarations such as functions, classes,
/// structs, enums, traits, and more. Use `Other` for
/// language-specific constructs that do not fit a standard category.
///
/// # Wire format (public JSON contract)
///
/// Unit variants serialize as a bare string (`"Function"`); the `Other`
/// variant serializes as a single-keyed object (`{"Other": "macro"}`). DO
/// NOT add `#[serde(tag = "...")]` or rename variants — every language
/// binding has a hand-written deserializer matching this exact shape, and
/// any change breaks all bindings' `process()` tests simultaneously.
/// Covered by `tests/wire_format.rs`.

#[wasm_bindgen]
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum WasmStructureKind {
    Function = 0,
    Method = 1,
    Class = 2,
    Struct = 3,
    Interface = 4,
    Enum = 5,
    Module = 6,
    Trait = 7,
    Impl = 8,
    Namespace = 9,
    Other = 10,
}

#[allow(clippy::derivable_impls)]
impl Default for WasmStructureKind {
    fn default() -> Self {
        Self::Function
    }
}

impl WasmStructureKind {
    /// Returns the serde wire string for this variant (e.g. `"stop"`, `"tool_calls"`).
    pub fn to_api_str(self) -> &'static str {
        match self {
            Self::Function => "Function",
            Self::Method => "Method",
            Self::Class => "Class",
            Self::Struct => "Struct",
            Self::Interface => "Interface",
            Self::Enum => "Enum",
            Self::Module => "Module",
            Self::Trait => "Trait",
            Self::Impl => "Impl",
            Self::Namespace => "Namespace",
            Self::Other => "Other",
        }
    }

    /// Parses a serde wire string and returns the corresponding variant, or None if unrecognized.
    pub fn from_api_str(s: &str) -> Option<Self> {
        match s {
            "Function" => Some(Self::Function),
            "Method" => Some(Self::Method),
            "Class" => Some(Self::Class),
            "Struct" => Some(Self::Struct),
            "Interface" => Some(Self::Interface),
            "Enum" => Some(Self::Enum),
            "Module" => Some(Self::Module),
            "Trait" => Some(Self::Trait),
            "Impl" => Some(Self::Impl),
            "Namespace" => Some(Self::Namespace),
            "Other" => Some(Self::Other),
            _ => None,
        }
    }
}

