#[derive(serde::Deserialize, Default)]
#[serde(default)]
pub struct ProcessConfigInput {
    #[serde(rename = "language")]
    pub language: Option<String>,
    #[serde(rename = "structure")]
    pub structure: Option<bool>,
    #[serde(rename = "imports")]
    pub imports: Option<bool>,
    #[serde(rename = "exports")]
    pub exports: Option<bool>,
    #[serde(rename = "comments")]
    pub comments: Option<bool>,
    #[serde(rename = "docstrings")]
    pub docstrings: Option<bool>,
    #[serde(rename = "symbols")]
    pub symbols: Option<bool>,
    #[serde(rename = "diagnostics")]
    pub diagnostics: Option<bool>,
    #[serde(rename = "chunkMaxSize")]
    pub chunk_max_size: Option<usize>,
    #[serde(rename = "dataExtraction")]
    pub data_extraction: Option<bool>,
}

impl From<ProcessConfigInput> for tree_sitter_language_pack::ProcessConfig {
    fn from(val: ProcessConfigInput) -> Self {
        let mut out = Self::default();
        if let Some(v) = val.language {
            out.language = v.into();
        }
        if let Some(v) = val.structure {
            out.structure = v.into();
        }
        if let Some(v) = val.imports {
            out.imports = v.into();
        }
        if let Some(v) = val.exports {
            out.exports = v.into();
        }
        if let Some(v) = val.comments {
            out.comments = v.into();
        }
        if let Some(v) = val.docstrings {
            out.docstrings = v.into();
        }
        if let Some(v) = val.symbols {
            out.symbols = v.into();
        }
        if let Some(v) = val.diagnostics {
            out.diagnostics = v.into();
        }
        if let Some(v) = val.chunk_max_size {
            out.chunk_max_size = v.into();
        }
        if let Some(v) = val.data_extraction {
            out.data_extraction = v.into();
        }
        out
    }
}

/// Detect language name from a file extension (without leading dot).
///
/// Returns `None` for unrecognized extensions. The match is case-insensitive.
#[wasm_bindgen(js_name = "detectLanguageFromExtension")]
pub fn detect_language_from_extension(ext: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_extension(&ext).map(Into::into)
}

/// Detect language name from a file path.
///
/// Extracts the file extension and looks it up. Returns `None` if the
/// path has no extension or the extension is not recognized.
#[wasm_bindgen(js_name = "detectLanguageFromPath")]
pub fn detect_language_from_path(path: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_path(&path).map(Into::into)
}

/// Detect language name from file content using the shebang line (`#!`).
///
/// Inspects only the first line of `content`. If it begins with `#!`, the
/// interpreter name is extracted and mapped to a language name.
///
/// Handles common patterns:
/// - `#!/usr/bin/env python3` → `"python"`
/// - `#!/bin/bash` → `"bash"`
/// - `#!/usr/bin/env node` → `"javascript"`
///
/// The `-S` flag accepted by some `env` implementations is skipped automatically.
/// Version suffixes (e.g. `python3.11`, `ruby3.2`) are stripped before matching.
///
/// Returns `None` when content does not start with `#!`, the shebang is
/// malformed, or the interpreter is not recognised.
#[wasm_bindgen(js_name = "detectLanguageFromContent")]
pub fn detect_language_from_content(content: String) -> Option<String> {
    tree_sitter_language_pack::detect_language_from_content(&content).map(Into::into)
}

