/// Get a tree-sitter `Language` by name using the global registry.
///
/// Resolves language aliases (e.g., `"shell"` maps to `"bash"`).
/// When the `download` feature is enabled (default), automatically downloads
/// the parser from GitHub releases if not found locally.
///
/// # Errors
///
/// Returns `Error.LanguageNotFound` if the language is not recognized,
/// or `Error.Download` if auto-download fails.
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "getLanguage")]
pub fn get_language(name: String) -> Result<WasmLanguage, JsValue> {
    let result = tree_sitter_language_pack::get_language(&name).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmLanguage {
        inner: Arc::new(result),
    })
}

/// Get a `Parser` pre-configured for the given language.
///
/// This is a convenience function that calls `get_language` and configures
/// a new parser in one step.
///
/// # Errors
///
/// Returns `Error.LanguageNotFound` if the language is not recognized, or
/// `Error.ParserSetup` if the language cannot be applied to the parser.
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "getParser")]
pub fn get_parser(name: String) -> Result<WasmParser, JsValue> {
    let result = tree_sitter_language_pack::get_parser(&name).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmParser {
        inner: Arc::new(std::sync::Mutex::new(result)),
    })
}

